1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Customer = { yearsWithMHPCO: number };
3	type QuoteInput = {
4	  customer: Customer;
5	  items: Item[];
6	  previousContracts: number;
7	};
8	
9	const PROCESSING_FEE = 5;
10	const NEWCOMER_PER_ITEM_SURCHARGE_RATE = 0.1;
11	const CURSED_SURCHARGE_RATE = 0.5;
12	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
13	const HIGH_ENCHANTMENT_THRESHOLD = 5;
14	const COMPONENT_BLOCK_SIZE = 3;
15	const COMPONENT_BLOCK_BASE = 60;
16	
17	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
18	
19	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
20	  sword: 100,
21	  amulet: 60,
22	  staff: 80,
23	  potion: 40,
24	  rune: 25,
25	  moonstone: 25,
26	};
27	
28	const basePremiumForItem = (item: Item): number =>
29	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
30	
31	const isNewcomer = (customer: Customer): boolean =>
32	  customer.yearsWithMHPCO === 0;
33	
34	const isHighlyEnchanted = (item: Item): boolean =>
35	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
36	
37	const isCursed = (item: Item): boolean => item.cursed === true;
38	
39	const surcharge = (base: number, applies: boolean, rate: number): number =>
40	  applies ? base * rate : 0;
41	
42	const premiumForItem = (item: Item, customer: Customer): number => {
43	  const base = basePremiumForItem(item);
44	  return (
45	    base +
46	    surcharge(base, isCursed(item), CURSED_SURCHARGE_RATE) +
47	    surcharge(base, isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE_RATE) +
48	    surcharge(base, isNewcomer(customer), NEWCOMER_PER_ITEM_SURCHARGE_RATE)
49	  );
50	};
51	
52	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
53	
54	const componentGroupBase = (items: Item[]): number => {
55	  const itemBase = basePremiumForItem(items[0]);
56	  if (items.length === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_BASE;
57	  return items.length * itemBase;
58	};
59	
60	const groupByType = (items: Item[]): Map<string, Item[]> => {
61	  const groups = new Map<string, Item[]>();
62	  for (const item of items) {
63	    const list = groups.get(item.type) ?? [];
64	    list.push(item);
65	    groups.set(item.type, list);
66	  }
67	  return groups;
68	};
69	
70	const componentGroupTotal = (
71	  groupItems: Item[],
72	  customer: Customer,
73	): number => {
74	  const groupBase = componentGroupBase(groupItems);
75	  return (
76	    groupBase +
77	    surcharge(groupBase, isNewcomer(customer), NEWCOMER_PER_ITEM_SURCHARGE_RATE)
78	  );
79	};
80	
81	const componentsTotal = (items: Item[], customer: Customer): number => {
82	  const groups = groupByType(items);
83	  return [...groups.values()].reduce(
84	    (sum, groupItems) => sum + componentGroupTotal(groupItems, customer),
85	    0,
86	  );
87	};
88	
89	const nonComponentsTotal = (items: Item[], customer: Customer): number =>
90	  items.reduce((sum, item) => sum + premiumForItem(item, customer), 0);
91	
92	export const quote = (input: QuoteInput): { premium: number } => {
93	  const components = input.items.filter(isComponent);
94	  const nonComponents = input.items.filter((item) => !isComponent(item));
95	  const itemsTotal =
96	    nonComponentsTotal(nonComponents, input.customer) +
97	    componentsTotal(components, input.customer);
98	  return { premium: Math.ceil(itemsTotal + PROCESSING_FEE) };
99	};
100	
101	export const claim = (_input: unknown): unknown => {
102	  return undefined;
103	};
